use std::mem;

struct Data<'a> { 
    value: &'a str,
}

// This function takes a reference and returns a new structure that holds the reference.
fn process_data(input_ref: &'static str) -> Data<'_> {
    let data = Data { value: input_ref };
    println!("Data created successfully with value: {}", data.value);
    data
}

// This function simulates needing the reference to outlive some local processing.
fn use_reference_later(input_ref: &'static str) -> Data<'_> {
    let result = process_data(input_ref);
    println!("Reference used later in scope. Value is still: {}", result.value);
    result
}

fn main() {
    let original_string: &'static str = "Guaranteed Data";

    // The lifetime concept here ensures that the reference passed into process_data 
    // (which comes from a 'static source) is valid throughout the scope of use_reference_later.
    let final_result = use_reference_later(original_string);

    println!("Final result processed. Value remains: {}", final_result.value);
}

