    source: &'a Source<'a>,
}

impl<'a> Builder<'a> {
    fn new(source: &'a Source<'a>) -> Self {
        Builder { source } 
    }

    fn finalize(&self) -> Result<&'a str, &'static str> {
        if self.source.data.contains('X') {
            Ok(self.source.data)
        } else {
            Err("Data is incomplete for finalization")
        }
    }
}

